CREATE OR REPLACE FUNCTION fpa_com_adress_mem_no_phone_no (as_memno char) RETURNS varchar AS $body$
DECLARE

  ls_return varchar(400);
  li_count integer;

BEGIN
  ls_return := trim(both pka_com_function.fp_get_member_address_pres(as_memno));

  li_count := position('โทรศัพท์' in ls_return);
  if li_count > 0 then
    ls_return := substr(ls_return,1,li_count - 1);
  else
    ls_return := ls_return;
  end if;

return ls_return;
exception when others then CALL spa_dberror('FPA_COM_ADRESS_MEM_NO_PHONE_NO');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
